## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "parserAssignment.pl",
  "contextForm.pl",
  "parserLinearRelation.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
($X, $Y) = random_subset(2, 'a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context("Numeric")->variables->are($X => 'Real', $Y => 'Real');
Context()->noreduce('(-x)-y', '(-x)+y');
parser::Assignment->Allow;
do {
  $m[0] = non_zero_random(-8,8,0.1);
  $m[1] = non_zero_random(-8,8,0.1);
} until ($m[0] != $m[1]);
$b[0] = non_zero_random(-8,8,0.1);
$b[1] = non_zero_random(-8,8,0.1);
$x = -($b[1] - $b[0])/($m[1] - $m[0]);
$y = $m[0]*$x + $b[0];
@right = map{Formula("$m[$_] $X + $b[$_]")->reduce} (0,1);
@f = map{Formula("$Y = $right[$_]")->reduce} (0,1);
$xis = Formula("$X = $x");
$yis = Formula("$Y = $y");
$solution = List($xis,$yis);
Context()->strings->remove("NONE");
Context()->strings->add(
  "no solutions" => {},
);
for (
  "no solution",
  "none",
  "there are no solutions",
  "the solution set is empty",
  "solution set is empty",
  "empty set",
  "∅",
  "{}",
  "{ }",
  "{  }",
  "{   }"
) {
  Context()->strings->add($_ => {alias => "no solutions"});
}
Context()->strings->add(
  "infinitely many solutions" => {},
);
for (
  "infinitely many",
  "infinite solution set",
  "infinite",
  "the solution set is infinite",
  "solution set is infinite"
) {
  Context()->strings->add($_ => {alias => "infinitely many solutions"});
}
$answer = $solution->cmp(
  mathQuillOpts => 'disabled'
);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the system of equations using substitution.

[`\newcommand{\amp}{&}\left\{
                  \begin{alignedat}{4}
                  \amp [$f[0]] \\
                  \amp [$f[1]]
                  \end{alignedat}
                  \right.
                `]

[@KeyboardInstructions('Write the solution in the format [`[$X] = \text{number}, [$Y] = \text{number}\text{.}`] If there is no solution, enter [|no solutions|]*. If there are infinitely many solutions, enter [|infinitely many solutions|]*.')@]**

[_]{$answer}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
